{% set property = frappe.get_all("Property", filters={"status": "Active"}, fields=["property_name", "address", "city", "country"], limit_page_length=1) %}
<div style="text-align:center; margin-bottom: 10px;">
{% if property %}
  <h2 style="margin-bottom:4px;">{{ property[0].property_name }}</h2>
  <div style="font-size: 11px; color:#555;">
    {{ property[0].address ~ ", " if property[0].address else "" }}{{ property[0].city }}, {{ property[0].country }}
  </div>
{% else %}
  <h2 style="margin-bottom:4px;">Hotel</h2>
{% endif %}
</div>
